ss="text-muted fw-bold">Password strength: Not started</small></div><div><label>Confirm Password</label><input class="form-control" id="confirmPassword" type="password" required></div></div></section><section class="module-card"><h4>Permissions</h4><p class="text-muted fw-bold">Read-only placeholders. Final access should come from the Roles & Permissions module.</p><div class="chip-list"><?php foreach($accountantPermissions as $p): ?><span class="chip"><i class="fa-solid fa-lock me-1"></i><?php echo sms_e($p); ?></span><?php endforeach; ?></div></section><section class="module-card"><h4>Documents</h4><div class="form-grid"><?php foreach(['Passport Photograph','CV / Resume','Academic Certificates','Appointment Letter','Identification Document'] as $i=>$label): ?><div><label><?php echo sms_e($label); ?></label><input class="form-control tracked-file" type="file" accept=".pdf,.jpg,.jpeg,.png" <?php echo $i===2?'multiple':''; ?>><div class="file-list">No file selected</div></div><?php endforeach; ?></div></section><section class="module-card"><div class="d-flex justify-content-end flex-wrap gap-2"><button class="module-btn btn-primary-soft" type="submit" data-mode="save">Save Accountant</button><button class="module-btn btn-outline-soft" type="submit" data-mode="save-add">Save & Add Another</button><button class="module-btn btn-muted-soft" type="reset">Reset Form</button><a class="module-btn btn-danger-soft" href="accountants.php">Cancel</a></div></section></form></div></div></div><script>(function(){var f=accountantForm,p=password,c=confirmPassword,m=passwordMeter,t=passwordStrengthText,mode='save';document.querySelectorAll('button[type="submit"]').forEach(function(b){b.onclick=function(){mode=b.dataset.mode||'save'}});p.oninput=function(){var v=p.value,s=0;if(v.length>=8)s++;if(/[A-Z]/.test(v))s++;if(/[0-9]/.test(v))s++;if(/[^A-Za-z0-9]/.test(v))s++;m.style.width=(s*25)+'%';m.style.background=['#dc2626','#dc2626','#d97706','#2563eb','#16a34a'][s];t.textContent='Password strength: '+['Not started','Weak','Fair','Good','Strong'][s]};document.querySelectorAll('.tracked-file').forEach(function(i){i.onchange=function(){var list=i.parentElement.querySelector('.file-list'),names=[].map.call(i.files,function(file){return file.name});list.textContent=names.length?names.join(', '):'No file selected'}});f.onsubmit=function(e){e.preventDefault();c.setCustomValidity(p.value!==c.value?'Passwords do not match.':'');if(!f.checkValidity()){f.reportValidity();return}saveAlert.style.display='block';if(mode==='save-add')setTimeout(function(){f.reset();m.style.width='0';t.textContent='Password strength: Not started'},500)}})();</script><?php require_once('includes/footer.php'); ?>